import React, { useEffect, useState, useCallback } from 'react';
import { useAuth } from '../context/AuthContext';
import { apiCall } from '../utils/api';

const AdminProducts = () => {
  const { user, token } = useAuth();
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all'); // all, visible, hidden
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [form, setForm] = useState({
    name: '',
    description: '',
    price: '',
    category: '',
    brand: '',
    image: '',
    stock: ''
  });
  const [imageFile, setImageFile] = useState(null);
  const [error, setError] = useState('');

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const res = await apiCall.get('/products', {
        headers: { Authorization: `Bearer ${token}` },
        params: { admin: true }
      });
      const raw = res.data.products || [];
      const unique = Array.from(new Map(raw.map(p => [p._id, p])).values());
      setProducts(unique);
    } catch (err) {
      console.error('Error fetching products', err);
    } finally {
      setLoading(false);
    }
  }, [token]);

  useEffect(() => {
    if (user?.role === 'admin') {
      fetchProducts();
    }
  }, [user, fetchProducts]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setImageFile(file);
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError('');
    try {
      let config = { headers: { Authorization: `Bearer ${token}` } };
      let data;

      if (imageFile) {
        data = new FormData();
        data.append('name', form.name);
        data.append('description', form.description);
        data.append('price', parseFloat(form.price));
        data.append('category', form.category);
        data.append('brand', form.brand);
        data.append('stock', parseInt(form.stock, 10));
        data.append('image', imageFile);
        config.headers['Content-Type'] = 'multipart/form-data';
      } else {
        data = {
          name: form.name,
          description: form.description,
          price: parseFloat(form.price),
          category: form.category,
          brand: form.brand,
          image: form.image,
          stock: parseInt(form.stock, 10)
        };
      }

      if (editingId) {
        await apiCall.put(`/products/${editingId}`, data, config);
        alert('✅ Product updated successfully!');
        setEditingId(null);
      } else {
        await apiCall.post('/products', data, config);
        alert('✅ Product added successfully!');
      }

      setForm({
        name: '',
        description: '',
        price: '',
        category: '',
        brand: '',
        image: '',
        stock: ''
      });
      setImageFile(null);
      setShowForm(false);
      fetchProducts();
    } catch (err) {
      setError(err.response?.data?.message || 'Error saving product');
    }
  };

  const handleEdit = (product) => {
    setEditingId(product._id);
    setForm({
      name: product.name,
      description: product.description || '',
      price: product.price,
      category: product.category,
      brand: product.brand,
      image: product.image || '',
      stock: product.stock
    });
    setShowForm(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this product?')) {
      try {
        await apiCall.delete(`/products/${id}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        alert('✅ Product deleted!');
        fetchProducts();
      } catch (err) {
        alert('❌ Failed to delete product');
      }
    }
  };

  const handleToggleVisibility = async (id, currentVisibility) => {
    try {
      await apiCall.put(
        `/products/${id}`,
        { visible: !currentVisibility },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      const newProducts = products.map(p =>
        p._id === id ? { ...p, visible: !currentVisibility } : p
      );
      setProducts(newProducts);
      alert(currentVisibility ? '🙈 Product hidden!' : '👁 Product visible!');
    } catch (err) {
      alert('❌ Failed to update visibility');
    }
  };

  const handleCancel = () => {
    setShowForm(false);
    setEditingId(null);
    setForm({
      name: '',
      description: '',
      price: '',
      category: '',
      brand: '',
      image: '',
      stock: ''
    });
    setImageFile(null);
    setError('');
  };

  // Filter and search products
  const filteredProducts = products.filter(p => {
    const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase()) ||
                         p.category.toLowerCase().includes(search.toLowerCase());
    
    if (filter === 'visible') return matchesSearch && p.visible;
    if (filter === 'hidden') return matchesSearch && !p.visible;
    return matchesSearch;
  });

  if (!user || user.role !== 'admin') {
    return null;
  }

  return (
    <div className="admin-container">
      <div className="products-header">
        <h1>📦 Products Management</h1>
        <button onClick={() => setShowForm(!showForm)} className="add-btn">
          {showForm ? '✕ Cancel' : '+ Add New Product'}
        </button>
      </div>

      {showForm && (
        <div className="product-form-container">
          <h2>{editingId ? 'Edit Product' : 'Add New Product'}</h2>
          {error && <div className="error-alert">{error}</div>}
          <form onSubmit={handleAdd} className="product-form">
            <div className="form-row">
              <input
                type="text"
                name="name"
                placeholder="Product Name"
                value={form.name}
                onChange={handleChange}
                required
              />
              <input
                type="number"
                name="price"
                placeholder="Price"
                value={form.price}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-row">
              <input
                type="text"
                name="category"
                placeholder="Category"
                value={form.category}
                onChange={handleChange}
                required
              />
              <input
                type="text"
                name="brand"
                placeholder="Brand"
                value={form.brand}
                onChange={handleChange}
                required
              />
            </div>

            <div className="form-row">
              <input
                type="number"
                name="stock"
                placeholder="Stock Quantity"
                value={form.stock}
                onChange={handleChange}
                required
              />
              <input
                type="text"
                name="image"
                placeholder="Image URL"
                value={form.image}
                onChange={handleChange}
              />
            </div>

            <textarea
              name="description"
              placeholder="Description (Optional)"
              value={form.description}
              onChange={handleChange}
              rows="3"
            />

            <div className="file-input-wrapper">
              <label>Or upload image file:</label>
              <input
                type="file"
                accept="image/*"
                onChange={handleFileChange}
              />
            </div>

            <div className="form-buttons">
              <button type="submit" className="save-btn">
                {editingId ? '💾 Update Product' : '✅ Add Product'}
              </button>
              <button type="button" onClick={handleCancel} className="cancel-btn">
                ✕ Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      <div className="products-controls">
        <div className="search-box">
          <input
            type="text"
            placeholder="🔍 Search products by name or category..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="search-input"
          />
        </div>

        <div className="filter-box">
          <select
            value={filter}
            onChange={(e) => setFilter(e.target.value)}
            className="filter-select"
          >
            <option value="all">All Products</option>
            <option value="visible">✅ Visible</option>
            <option value="hidden">🙈 Hidden</option>
          </select>
        </div>

        <div className="product-count">
          {filteredProducts.length} product(s)
        </div>
      </div>

      {loading ? (
        <p className="loading">Loading products...</p>
      ) : filteredProducts.length === 0 ? (
        <p className="no-products">No products found</p>
      ) : (
        <div className="products-table-wrapper">
          <table className="products-table">
            <thead>
              <tr>
                <th>Product Name</th>
                <th>Category</th>
                <th>Price</th>
                <th>Stock</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredProducts.map(product => (
                <tr key={product._id} className={!product.visible ? 'hidden-row' : ''}>
                  <td className="product-name">{product.name}</td>
                  <td>{product.category}</td>
                  <td className="price">₹{product.price.toLocaleString('en-IN')}</td>
                  <td className="stock">
                    <span className={product.stock < 5 ? 'low-stock' : ''}>
                      {product.stock}
                    </span>
                  </td>
                  <td className="status">
                    {product.visible ? (
                      <span className="status-visible">👁 Visible</span>
                    ) : (
                      <span className="status-hidden">🙈 Hidden</span>
                    )}
                  </td>
                  <td className="actions">
                    <button
                      className={`action-btn visibility-btn ${product.visible ? 'hide' : 'show'}`}
                      onClick={() => handleToggleVisibility(product._id, product.visible)}
                      title={product.visible ? 'Hide product' : 'Show product'}
                    >
                      {product.visible ? '👁 Hide' : '✅ Show'}
                    </button>
                    <button
                      className="action-btn edit-btn"
                      onClick={() => handleEdit(product)}
                      title="Edit product"
                    >
                      ✏ Edit
                    </button>
                    <button
                      className="action-btn delete-btn"
                      onClick={() => handleDelete(product._id)}
                      title="Delete product"
                    >
                      🗑 Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
};

export default AdminProducts;
